1	/*!
2	 * \file multi_gpu_loader.cc
3	 * \brief Implementation of a multi-GPU loader with loading-time sharding.
4	 */
5	#ifndef MLC_SINGLE_GPU_ONLY
6	#include <tvm/ffi/container/array.h>
7	#include <tvm/ffi/extra/json.h>
8	#include <tvm/ffi/function.h>
9	#include <tvm/ffi/optional.h>
10	#include <tvm/ffi/reflection/registry.h>
11	#include <tvm/runtime/device_api.h>
12	#include <tvm/runtime/disco/builtin.h>
13	#include <tvm/runtime/disco/disco_worker.h>
14	#include <tvm/runtime/vm/tensor_cache_support.h>
15	
16	#include <chrono>
17	#include <filesystem>
18	#include <fstream>
19	#include <functional>
20	#include <numeric>
21	#include <string>
22	#include <thread>
23	#include <unordered_map>
