29	namespace mlc {
30	namespace llm {
31	namespace multi_gpu {
32	
33	using tvm::Device;
34	using tvm::runtime::vm::TensorCacheMetadata;
35	using namespace tvm::runtime;
36	using tvm::ffi::Array;
37	using tvm::ffi::Function;
38	using tvm::ffi::Object;
39	using tvm::ffi::Optional;
40	using tvm::ffi::Shape;
41	using tvm::ffi::TypedFunction;
42	using DurationType = std::chrono::microseconds;
43	
44	class RangeTimer {
45	 public:
46	  explicit RangeTimer(DurationType* result)
47	      : start(std::chrono::high_resolution_clock::now()), result(result) {}
48	
49	  ~RangeTimer() {
50	    std::chrono::time_point<std::chrono::high_resolution_clock> end =
51	        std::chrono::high_resolution_clock::now();  //
52	    auto duration = end - start;
53	    (*result) += std::chrono::duration_cast<DurationType>(end - start);
54	  }
55	
56	 private:
57	  std::chrono::time_point<std::chrono::high_resolution_clock> start;
58	  DurationType* result;
59	};
60	
61	class PreprocessorPool {
62	 public:
63	  explicit PreprocessorPool(const ModelMetadata& model_metadata, Module vm_module) {
64	    for (const ModelMetadata::Param& param : model_metadata.params) {
65	      for (const ModelMetadata::Param::Preproc& preproc : param.preprocs) {
66	        const std::string& func_name = preproc.func_name;
67	        if (Function f = vm_module.defined()
68	                             ? vm_module->GetFunction(func_name, true).value_or(Function(nullptr))
69	                             : nullptr;
70	            f != nullptr) {
71	          preproc_funcs[func_name] = f;
72	        } else if (const auto f = Function::GetGlobal(func_name); f.has_value()) {
73	          preproc_funcs[func_name] = *f;
74	        } else {
75	          LOG(FATAL) << "ValueError: Undefined function: " << func_name;
76	        }
77	      }
78	    }
79	  }
80	
81	  Tensor Apply(Tensor param, const ModelMetadata::Param& param_info) const {
82	    for (const ModelMetadata::Param::Preproc& preproc : param_info.preprocs) {
83	      const std::string& func_name = preproc.func_name;
84	      Tensor param_in = param;
85	      param = Tensor::Empty(preproc.out_shape, preproc.out_dtype, param->device);
86	      TVM_FFI_ICHECK(preproc_funcs.count(func_name));
87	      DLTensor dl_param_in = *param_in.operator->();
88	      DLTensor dl_param = *param.operator->();
89	      preproc_funcs.at(func_name)(&dl_param_in, &dl_param);
90	    }
91	    return param;
92	  }
93	
94	 private:
95	  std::unordered_map<std::string, TypedFunction<void(DLTensor*, DLTensor*)>> preproc_funcs;
96	};
97	
98	struct ParamInfo {
99	  const TensorCacheMetadata::FileRecord* file;
100	  const TensorCacheMetadata::FileRecord::ParamRecord* param;
101	};
102	
103	Tensor RecvFromGlobalWorker0(Device device, const ModelMetadata::Param& param_info) {
104	  Shape shape = param_info.preprocs.empty() ? param_info.shape : param_info.preprocs[0].in_shape;
105	  Tensor result = Tensor::Empty(shape, param_info.dtype, device);
106	  RecvFromWorker0(result);
107	  return result;
108	}
109	
110	Tensor BroadcastOrShardAndScatter(Tensor param, const ModelMetadata::Param& param_info,
111	                                  int num_shards, const PreprocessorPool& preprocs) {
112	  bool needs_sharding = !param_info.preprocs.empty();
113	  if (!needs_sharding) {
114	    BroadcastFromWorker0(param, /*in_group=*/true, param);
115	    return param;
116	  }
117	  Device device = param->device;
118	  Shape shape = param_info.preprocs.back().out_shape;
119	  DLDataType dtype = param_info.preprocs.back().out_dtype;
120	  TVM_FFI_ICHECK(shape.size() >= 1 && shape[0] == num_shards)
121	      << "ValueError: The first dimension of the output shape must be equal to the "
122	      << "number of shards, but got: " << shape << " and num_shards = " << num_shards;
123	  param = preprocs.Apply(param, param_info);
124	  Tensor result = Tensor::Empty(Shape(shape.begin() + 1, shape.end()), dtype, device);
125	  ScatterFromWorker0(param, /*in_group=*/true, result);
126	  return result;
127	}
128	
129	Tensor ReceiveBroadcastedOrSharded(Device device, const ModelMetadata::Param& param_info,
130	                                   int num_shards) {
131	  bool needs_sharding = !param_info.preprocs.empty();
132	  Tensor result;
133	  if (needs_sharding) {
134	    Shape shape = param_info.preprocs.back().out_shape;
135	    DLDataType dtype = param_info.preprocs.back().out_dtype;
136	    result = Tensor::Empty(Shape(shape.begin() + 1, shape.end()), dtype, device);
137	    ScatterFromWorker0(std::nullopt, /*in_group=*/true, result);
138	  } else {
139	    result = Tensor::Empty(param_info.shape, param_info.dtype, device);
140	    BroadcastFromWorker0(result, /*in_group=*/true, result);
141	  }
142	  return result;
143	}
144	
145	std::string FormatDuration(DurationType duration) {
146	  std::ostringstream os;
147	  auto float_seconds = std::chrono::duration_cast<std::chrono::duration<float>>(duration).count();
148	  os << std::fixed << std::setprecision(3) << float_seconds << " s";
149	  return os.str();
150	}
