152	Array<Optional<Tensor>> LoadMultiGPU(const std::string& model_path, Module vm_module,
153	                                     const std::string& model_config_str) {
154	  DiscoWorker* worker = DiscoWorker::ThreadLocal();
155	  Device device = worker->default_device;
156	  int worker_id = worker->worker_id;
157	  int group_size = worker->num_workers / worker->num_groups;
158	  int num_shards = group_size;
159	  int group_id = worker_id / group_size;
160	  LOG(INFO) << "[Worker #" << worker_id << "] Loading model to device: " << device;
161	  // Step 0. Initialize metadata and paths
162	  TensorCacheMetadata tensor_cache_metadata = TensorCacheMetadata::Load(model_path);
163	  tvm::ffi::json::Value model_config = tvm::ffi::json::Parse(model_config_str);
164	  ModelMetadata model_metadata =
165	      ModelMetadata::FromModule(vm_module, model_config.cast<tvm::ffi::json::Object>());
166	  TVM_FFI_ICHECK_EQ(model_metadata.tensor_parallel_shards, num_shards)
167	      << "ValueError: The model is compiled using `--tensor-parallel-shards="
168	      << model_metadata.tensor_parallel_shards
169	      << "`, but mlc-chat-config.json is configured to use " << num_shards << " GPUs. "
170	      << "Please set \"tensor_parallel_shards\" in mlc-chat-config.json to "
171	      << model_metadata.tensor_parallel_shards;
172	  // Step 1. Extract auxiliary information
173	  PreprocessorPool preprocs(model_metadata, vm_module);
174	  std::unordered_map<std::string, ModelMetadata::Param> param_name2info;
175	  for (const ModelMetadata::Param& param : model_metadata.params) {
176	    param_name2info[param.name] = param;
177	  }
178	  // Step 2. Load, preprocess and shard all the parameters
179	  std::unordered_map<std::string, Tensor> sharded_params;
180	  if (worker_id == 0) {
181	    DurationType time_loading(0);
182	    DurationType time_preproc(0);
183	    ProgressBar progress_bar(model_metadata.params.size());
184	    LOG(INFO) << "Loading parameters...";
185	    for (const TensorCacheMetadata::FileRecord& record : tensor_cache_metadata.records) {
186	      Array<Tensor> loaded_params;
187	      {
188	        RangeTimer _(&time_loading);
189	        std::string raw_data_buffer;
190	        loaded_params = record.Load(device, model_path, &raw_data_buffer);
191	        DeviceAPI::Get(device)->StreamSync(device, nullptr);
192	      }
193	      // For each parameter in the shard file, preprocess and shard it
194	      for (size_t i = 0; i < record.records.size(); ++i, progress_bar.Progress()) {
195	        RangeTimer _(&time_preproc);
196	        const std::string& param_name = record.records[i].name;
197	        const ModelMetadata::Param& param_info = param_name2info.at(param_name);
198	        for (int group_id : param_info.pipeline_stages) {
199	          if (group_id == 0) {
200	            // Broadcast or shard-scatter this parameter to all workers in worker group 0.
201	            sharded_params[param_name] =
202	                BroadcastOrShardAndScatter(loaded_params[i], param_info, num_shards, preprocs);
203	          } else {
204	            // Send this parameter to the first worker of the worker group of "group_id",
205	            // and let that first worker to process this parameter.
206	            SendToWorker(loaded_params[i], /*receiver_id=*/group_id * group_size);
207	          }
208	        }
209	        DeviceAPI::Get(device)->StreamSync(device, nullptr);
210	      }
211	    }
212	    LOG(INFO) << "Loading done. Time used:" << std::fixed << std::setprecision(3)  //
213	              << " Loading " << FormatDuration(time_loading) << " Preprocessing "
214	              << FormatDuration(time_preproc) << ".";
215	  } else {
216	    for (const TensorCacheMetadata::FileRecord& record : tensor_cache_metadata.records) {
217	      for (size_t i = 0; i < record.records.size(); ++i) {
218	        const std::string& param_name = record.records[i].name;
219	        const ModelMetadata::Param& param_info = param_name2info.at(param_name);
220	        if (std::find(param_info.pipeline_stages.begin(), param_info.pipeline_stages.end(),
221	                      group_id) == param_info.pipeline_stages.end()) {
222	          // This worker group doesn't need to hold a copy of this parameter.
223	          continue;
224	        }
225	
226	        if (worker_id % group_size == 0) {
227	          // The worker is the first worker of its worker group (while not the first worker group).
228	          // Receive the full parameter from the global worker 0.
229	          Tensor full_param = RecvFromGlobalWorker0(device, param_info);
230	          // Broadcast or shard-scatter this parameter to all workers in its worker group.
231	          sharded_params[param_name] =
232	              BroadcastOrShardAndScatter(full_param, param_info, num_shards, preprocs);
233	        } else {
234	          // The worker is not the first worker of its worker group.
235	          // Receive from the first worker in the its worker group.
236	          sharded_params[param_name] = ReceiveBroadcastedOrSharded(device, param_info, num_shards);
237	        }
238	      }
239	    }
240	  }
241	
242	  // Step 3. Reorder the sharded parameters according to the order in model_metadata
243	  Array<Optional<Tensor>> shards;
244	  shards.reserve(model_metadata.params.size());
245	  for (const ModelMetadata::Param& param : model_metadata.params) {
246	    const auto& it = sharded_params.find(param.name);
247	    shards.push_back(it == sharded_params.end() ? Optional<Tensor>() : it->second);
248	  }
249	  return shards;
250	}
251	
252	Array<Optional<Tensor>> LoadMultiGPUPresharded(const std::string& model_path, Module vm_module,
253	                                               const std::string& model_config_str) {
254	  DiscoWorker* worker = DiscoWorker::ThreadLocal();
255	  Device device = worker->default_device;
256	  int worker_id = worker->worker_id;
257	  int group_size = worker->num_workers / worker->num_groups;
258	  int num_shards = group_size;
259	  int group_id = worker_id / group_size;
260	  int local_worker_id = worker_id % group_size;
261	  LOG(INFO) << "[Worker #" << worker_id << "] Loading model to device: " << device;
262	  // Step 0. Initialize metadata and paths
263	  TensorCacheMetadata tensor_cache_metadata = TensorCacheMetadata::Load(model_path);
264	  tvm::ffi::json::Value model_config = tvm::ffi::json::Parse(model_config_str);
265	  ModelMetadata model_metadata =
266	      ModelMetadata::FromModule(vm_module, model_config.cast<tvm::ffi::json::Object>());
267	
268	  std::unordered_map<std::string, ParamInfo> param_info_map;
269	  for (const TensorCacheMetadata::FileRecord& file_record : tensor_cache_metadata.records) {
270	    for (const TensorCacheMetadata::FileRecord::ParamRecord& param_record : file_record.records) {
271	      const std::string& param_name = param_record.name;
272	      param_info_map[param_name] = ParamInfo{&file_record, &param_record};
273	    }
274	  }
275	
276	  Array<Optional<Tensor>> params;
277	  const TensorCacheMetadata::FileRecord* current_file_;
278	  std::string current_file_stream_;
279	  params.reserve(model_metadata.params.size());
280	  DurationType time_loading(0);
281	  for (const ModelMetadata::Param& param : model_metadata.params) {
282	    RangeTimer _(&time_loading);
283	    if (std::find(param.pipeline_stages.begin(), param.pipeline_stages.end(), group_id) ==
284	        param.pipeline_stages.end()) {
285	      // This worker group doesn't need to hold a copy of this parameter.
286	      params.push_back(Optional<Tensor>());
287	      continue;
288	    }
289	    bool needs_sharding = !param.preprocs.empty();
290	    std::string param_name =
291	        needs_sharding ? static_cast<const std::stringstream&>(
292	                             std::stringstream() << param.name << "_shard-" << local_worker_id)
293	                             .str()
294	                       : std::string(param.name);
295	    auto it = param_info_map.find(param_name);
296	    TVM_FFI_ICHECK(it != param_info_map.end())
297	        << "ValueError: Cannot find parameter: " << param_name;
298	    const ParamInfo& param_info = (*it).second;
299	    const TensorCacheMetadata::FileRecord::ParamRecord* param_record = param_info.param;
300	    const TensorCacheMetadata::FileRecord* file_record = param_info.file;
301	
302	    if (file_record != current_file_) {
303	      current_file_ = file_record;
304	      file_record->Load(device, model_path, &current_file_stream_);
305	    }
306	
307	    params.push_back(param_record->Load(device, &current_file_stream_));
308	  }
309	  SyncWorker();
310	  if (worker_id == 0) {
311	    LOG(INFO) << "Loading done. Time used: " << FormatDuration(time_loading) << ".";
312	  }
313	  return params;
314	}
315	
316	TVM_FFI_STATIC_INIT_BLOCK() {
317	  namespace refl = tvm::ffi::reflection;
318	  refl::GlobalDef()
319	      .def("mlc.multi_gpu.LoadMultiGPU", LoadMultiGPU)
320	      .def("mlc.multi_gpu.LoadMultiGPUPresharded", LoadMultiGPUPresharded);
321	}
322	
323	}  // namespace multi_gpu
324	}  // namespace llm
325	}  // namespace mlc
326	
327	#endif  // MLC_SINGLE_GPU_ONLY
